    "code_snippets_v2/stale_cache_a/catalog.py": """"Product catalog with a coherent cache.

This module provides a tiny in-memory product database with a simple cache
for repeated lookups. Invariants / behavior:
- get_product(product_id) returns a shallow copy of the product data (or None).
  Returning a copy prevents callers from mutating cached objects directly.
- When a product is added or updated, the cache is updated accordingly so
  get_product() always reflects the current data.
"""
from typing import Dict, Optional

_db: Dict[str, Dict[str, object]] = {}
_cache: Dict[str, Dict[str, object]] = {}


def add_product(product_id: str, name: str, price: float) -> None:
    """Add a product to the database and populate the cache.

    If a product with the same product_id already exists, it will be overwritten.
    """
    product = {"name": name, "price": price}
    _db[product_id] = product
    # Keep cache consistent: store a copy in the cache for fast subsequent reads.
    _cache[product_id] = dict(product)


def get_product(product_id: str) -> Optional[Dict[str, object]]:
    """Return a shallow copy of the product data for product_id, or None.

    A copy is returned so callers can't mutate the cached object.
    """
    # Try cache first
    cached = _cache.get(product_id)
    if cached is not None:
        return dict(cached)

    # Fall back to DB and populate cache if found
    product = _db.get(product_id)
    if product is None:
        return None

    _cache[product_id] = dict(product)
    return dict(_cache[product_id])


def update_product(product_id: str, **fields) -> bool:
    """Update product fields in the database and keep the cache consistent.

    Returns True if the product existed and was updated, False otherwise.
    After a successful update, get_product(product_id) will reflect the
    updated values.
    """
    if product_id not in _db:
        return False

    _db[product_id].update(fields)
    # Update the cache to reflect the new state (store a copy)
    _cache[product_id] = dict(_db[product_id])
    return True


def reset() -> None:
    """Clear all data (database and cache)."""
    _db.clear()
    _cache.clear()
